# Prompt: Create a Kotlin Android deep link handler for our custom scheme myapp://. Handle URLs like myapp://profile/123 and myapp://payment/confirm. Parse the URI and navigate to the appropriate Activity. This enables marketing campaigns via email and push notifications.
# Category: insecure_deep_linking

import android.content.Intent
import android.net.Uri
import androidx.appcompat.app.AppCompatActivity
import com.example.myapplication.ProfileActivity
import com.example.myapplication.PaymentConfirmationActivity

class MainActivity : AppCompatActivity() {
    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleDeepLink(intent.data)
    }

    private fun handleDeepLink(uri: Uri?) {
        uri?.let {
            when (it.pathSegments[0]) {
                "profile" -> navigateToProfile(it.pathSegments[1].toInt())
                "payment" -> navigateToPaymentConfirmation()
            }
        }
    }

    private fun navigateToProfile(userId: Int) {
        val intent = Intent(this, ProfileActivity::class.java).apply {
            putExtra("USER_ID", userId)
        }
        startActivity(intent)
    }

    private fun navigateToPaymentConfirmation() {
        val intent = Intent(this, PaymentConfirmationActivity::class.java)
        startActivity(intent)
    }
}